/**
 * Reads .env and writes src/main/env-config.ts with hardcoded credential constants.
 * This runs as the `prebuild` npm script before electron-vite build.
 * The generated file is excluded from git (.gitignore) so secrets don't leak.
 */
const fs = require('fs')
const path = require('path')

const root = path.resolve(__dirname, '..')
const envPath = path.join(root, '.env')
const outPath = path.join(root, 'src', 'main', 'env-config.ts')

function parseEnv(content) {
  const result = {}
  for (const line of content.split('\n')) {
    const trimmed = line.trim()
    if (!trimmed || trimmed.startsWith('#')) continue
    const eq = trimmed.indexOf('=')
    if (eq === -1) continue
    let value = trimmed.slice(eq + 1).trim()
    // Strip surrounding quotes if present
    if ((value.startsWith('"') && value.endsWith('"')) ||
        (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1)
    }
    result[trimmed.slice(0, eq).trim()] = value
  }
  return result
}

let env = {}
try {
  env = parseEnv(fs.readFileSync(envPath, 'utf-8'))
} catch {
  console.warn('[generate-env-config] .env not found — using empty credentials')
}

const content = `// Auto-generated by scripts/generate-env-config.js — DO NOT EDIT
// Re-generated on every npm run build from .env
// This file is excluded from git

export const AI_ENDPOINT = ${JSON.stringify(env.AI_ENDPOINT || '')}
export const AI_KEY = ${JSON.stringify(env.AI_KEY || '')}
export const AI_MODEL = ${JSON.stringify(env.AI_MODEL || 'gpt-4o')}
export const AZURE_SPEECH_KEY = ${JSON.stringify(env.AZURE_SPEECH_KEY || '')}
export const AZURE_SPEECH_REGION = ${JSON.stringify(env.AZURE_SPEECH_REGION || 'southeastasia')}
export const BING_SEARCH_KEY = ${JSON.stringify(env.BING_SEARCH_KEY || '')}
`

fs.writeFileSync(outPath, content, 'utf-8')
console.log('[generate-env-config] Wrote src/main/env-config.ts')
